import { createRouter, createWebHistory } from 'vue-router'
import LoginVista from '../vistas/LoginVista.vue'
import ChatVista from '../vistas/ChatVista.vue'
import RegistroVista from '../vistas/RegistroVista.vue'

const routes = [
  {
    path: '/',
    redirect: '/login'
  },
  {
    path: '/login',
    name: 'login',
    component: LoginVista
  },
  {
    path: '/chat',
    name: 'chat',
    component: ChatVista
  },
  {
    path: '/registro',
    name: 'registro',
    component: RegistroVista
  }
]

const router = createRouter({
  history: createWebHistory('/chat-empresarial/'),
  routes
})

export default router

import { createRouter, createWebHistory } from 'vue-router'
import LoginVista from '../vistas/LoginVista.vue'
import ChatVista from '../vistas/ChatVista.vue'
import RegistroVista from '../vistas/RegistroVista.vue'

const routes = [
  {
    path: '/',
    redirect: '/login'
  },
  {
    path: '/login',
    name: 'login',
    component: LoginVista
  },
  {
    path: '/chat',
    name: 'chat',
    component: ChatVista
  },
  {
    path: '/registro',
    name: 'registro',
    component: RegistroVista
  }
]

const basePath = import.meta.env.VITE_BASE_PATH || '/'
const router = createRouter({
  history: createWebHistory(basePath),
  routes
})

export default router

// Servicios API para la aplicación Vue.js
import axios from 'axios'

const API_BASE_URL = 'http://localhost:8080/chat-empresarial/api/v1'

class ServicioAPI {
  constructor() {
    this.cliente = axios.create({
      baseURL: API_BASE_URL,
      timeout: 10000
    })

    // Interceptor para agregar token JWT
    this.cliente.interceptors.request.use(
      (config) => {
        const token = localStorage.getItem('token')
        if (token) {
          config.headers.Authorization = `Bearer ${token}`
        }
        return config
      },
      (error) => Promise.reject(error)
    )

    // Interceptor para manejar errores
    this.cliente.interceptors.response.use(
      (response) => response,
      (error) => {
        if (error.response?.status === 401) {
          // Token expirado o inválido
          localStorage.removeItem('token')
          localStorage.removeItem('usuario')
          window.location.href = '/login'
        }
        return Promise.reject(error)
      }
    )
  }

  // ========== AUTENTICACIÓN ==========

  async iniciarSesion(email, contraseña) {
    const { data } = await this.cliente.post('/usuarios/login', {
      email: email,
      password: contraseña
    })
    return data
  }

  async registrarse(nombreUsuario, email, contraseña) {
    const { data } = await this.cliente.post('/usuarios/register', {
      username: nombreUsuario,
      email: email,
      password: contraseña
    })
    return data
  }

  async actualizarPerfil(fotoUrl, estado) {
    const { data } = await this.cliente.put('/usuarios/perfil', {
      fotoUrl: fotoUrl,
      estado: estado
    })
    return data
  }

  async obtenerUsuarios() {
    const { data } = await this.cliente.get('/usuarios')
    return data
  }

  // ========== CONVERSACIONES ==========

  async obtenerConversaciones() {
    const { data } = await this.cliente.get('/conversaciones')
    return data
  }

  async crearConversacionPrivada(idOtroUsuario) {
    const { data } = await this.cliente.post('/conversaciones', {
      tipo: 'PRIVADA',
      participanteIds: [idOtroUsuario]
    })
    return data
  }

  async crearGrupo(nombre, participantesIds) {
    const { data } = await this.cliente.post('/conversaciones', {
      tipo: 'GRUPO',
      nombre: nombre,
      participanteIds: participantesIds
    })
    return data
  }

  async obtenerConversacion(idConversacion) {
    const { data } = await this.cliente.get(`/conversaciones/${idConversacion}`)
    return data
  }

  async añadirParticipante(idConversacion, idUsuario) {
    const { data } = await this.cliente.post(`/conversaciones/${idConversacion}/participantes`, {
      usuarioId: idUsuario
    })
    return data
  }

  // ========== MENSAJES ==========

  async enviarMensaje(nuevoMensaje) {
    const { data } = await this.cliente.post('/mensajes', nuevoMensaje)
    return data
  }

  async obtenerMensajes(idConversacion, limite = 50) {
    const { data } = await this.cliente.get(
      `/mensajes/conversacion/${idConversacion}?limite=${limite}`
    )
    return data
  }

  async marcarMensajeLeido(idMensaje) {
    const { data } = await this.cliente.post(
      `/mensajes/${idMensaje}/leido`
    )
    return data
  }

  async marcarConversacionLeida(idConversacion) {
    const { data } = await this.cliente.post(
      `/mensajes/conversacion/${idConversacion}/leidos`
    )
    return data
  }

  // ========== WEBSOCKET ==========

  conectarWebSocket(idConversacion, idUsuario, token) {
    const url = `ws://localhost:8080/chat-empresarial/ws/conversacion/${idConversacion}/usuario/${idUsuario}?token=${token}`
    console.log('Intentando conectar WebSocket a:', url)

    const ws = new WebSocket(url)

    // Configurar headers manualmente no funciona en WebSocket,
    // así que pasamos el token en la URL (alternativa: usar socket.io)
    ws.onopen = () => {
      console.log('WebSocket conectado')
      // Enviar token en primer mensaje si es necesario
    }

    ws.onerror = (error) => {
      console.error('Error WebSocket:', error)
    }

    return ws
  }
}

export const servicioApi = new ServicioAPI()

// Servicios API para la aplicación Vue.js
import axios from 'axios'

// Usar variables de entorno Vite (VITE_API_BASE_URL, VITE_WS_BASE_URL). Si no están,
// por defecto se utiliza ruta relativa '/api/v1' (útil para servir backend y frontend juntos).
const API_BASE_URL = import.meta.env.VITE_API_BASE_URL || (window.location.origin + '/api/v1')

class ServicioAPI {
  constructor() {
    this.cliente = axios.create({
      baseURL: API_BASE_URL,
      timeout: 10000
    })

    // Interceptor para agregar token JWT
    this.cliente.interceptors.request.use(
      (config) => {
        const token = localStorage.getItem('token')
        if (token) {
          config.headers.Authorization = `Bearer ${token}`
        }
        return config
      },
      (error) => Promise.reject(error)
    )

    // Interceptor para manejar errores
    this.cliente.interceptors.response.use(
      (response) => response,
      (error) => {
        if (error.response?.status === 401) {
          // Token expirado o inválido
          localStorage.removeItem('token')
          localStorage.removeItem('usuario')
          window.location.href = '/login'
        }
        return Promise.reject(error)
      }
    )
  }

  // ========== AUTENTICACIÓN ==========

  async iniciarSesion(email, contraseña) {
    const { data } = await this.cliente.post('/usuarios/login', {
      email: email,
      password: contraseña
    })
    return data
  }

  async registrarse(nombreUsuario, email, contraseña) {
    const { data } = await this.cliente.post('/usuarios/register', {
      username: nombreUsuario,
      email: email,
      password: contraseña
    })
    return data
  }

  async actualizarPerfil(fotoUrl, estado) {
    const { data } = await this.cliente.put('/usuarios/perfil', {
      fotoUrl: fotoUrl,
      estado: estado
    })
    return data
  }

  async obtenerUsuarios() {
    const { data } = await this.cliente.get('/usuarios')
    return data
  }

  // ========== CONVERSACIONES ==========

  async obtenerConversaciones() {
    const { data } = await this.cliente.get('/conversaciones')
    return data
  }

  async crearConversacionPrivada(idOtroUsuario) {
    const { data } = await this.cliente.post('/conversaciones', {
      tipo: 'PRIVADA',
      participanteIds: [idOtroUsuario]
    })
    return data
  }

  async crearGrupo(nombre, participantesIds) {
    const { data } = await this.cliente.post('/conversaciones', {
      tipo: 'GRUPO',
      nombre: nombre,
      participanteIds: participantesIds
    })
    return data
  }

  async obtenerConversacion(idConversacion) {
    const { data } = await this.cliente.get(`/conversaciones/${idConversacion}`)
    return data
  }

  async añadirParticipante(idConversacion, idUsuario) {
    const { data } = await this.cliente.post(`/conversaciones/${idConversacion}/participantes`, {
      usuarioId: idUsuario
    })
    return data
  }

  // ========== MENSAJES ==========

  async enviarMensaje(nuevoMensaje) {
    const { data } = await this.cliente.post('/mensajes', nuevoMensaje)
    return data
  }

  async obtenerMensajes(idConversacion, limite = 50) {
    const { data } = await this.cliente.get(
      `/mensajes/conversacion/${idConversacion}?limite=${limite}`
    )
    return data
  }

  async marcarMensajeLeido(idMensaje) {
    const { data } = await this.cliente.post(
      `/mensajes/${idMensaje}/leido`
    )
    return data
  }

  async marcarConversacionLeida(idConversacion) {
    const { data } = await this.cliente.post(
      `/mensajes/conversacion/${idConversacion}/leidos`
    )
    return data
  }

  // ========== WEBSOCKET ==========

  conectarWebSocket(idConversacion, idUsuario, token) {
    const wsBaseFromEnv = import.meta.env.VITE_WS_BASE_URL
    const base = wsBaseFromEnv || API_BASE_URL.replace(/^http/, 'ws').replace(/\/api\/v1$/, '')
    const url = `${base}/ws/conversacion/${idConversacion}/usuario/${idUsuario}?token=${token}`
    console.log('Intentando conectar WebSocket a:', url)

    const ws = new WebSocket(url)

    // Configurar headers manualmente no funciona en WebSocket,
    // así que pasamos el token en la URL (alternativa: usar socket.io)
    ws.onopen = () => {
      console.log('WebSocket conectado')
      // Enviar token en primer mensaje si es necesario
    }

    ws.onerror = (error) => {
      console.error('Error WebSocket:', error)
    }

    return ws
  }
}

export const servicioApi = new ServicioAPI()

#!/bin/bash set -euo pipefail
WILDFLY_HOME=/opt/jboss/wildfly
echo "[entrypoint] Configurando datasource si corresponde..."
if [ -n "${DB_HOST:-}" ] && [ -n "${DB_NAME:-}" ] && [ -n "${DB_USER:-}" ] && [ -n "${DB_PASSWORD:-}" ]; then DB_PORT=${DB_PORT:-5432} DB_URL="jdbc:postgresql://${DB_HOST}:${DB_PORT}/${DB_NAME}" echo "[entrypoint] Añadiendo módulo y driver PostgreSQL y datasource ChatDS" ${WILDFLY_HOME}/bin/jboss-cli.sh --command="embed-server --std-out=echo;module add --name=org.postgresql --resources=${WILDFLY_HOME}/standalone/deployments/postgresql.jar --dependencies=javax.api,javax.transaction.api;jdbc-driver add --driver-name=postgresql --driver-module-name=org.postgresql --driver-class-name=org.postgresql.Driver;data-source add --name=ChatDS --jndi-name=java:/ChatDS --driver-name=postgresql --connection-url='${DB_URL}' --user-name='${DB_USER}' --password='${DB_PASSWORD}' --use-ccm=false;stop-embedded-server" else echo "[entrypoint] Variables de BD no proporcionadas, omitiendo creación de datasource (usando JNDI existente si aplica)." fi
echo "[entrypoint] Iniciando WildFly..." exec ${WILDFLY_HOME}/bin/standalone.sh -b 0.0.0.0 -Djboss.http.port=${PORT:-8080}
